const raw = $json.output;
// Parse the JSON stringconst
const parsed = JSON.parse(raw);

return parsed;

const data = $('Parse JSON code').item.json;
// Get the copied doc ID from your Copy File node
const docId = $json.id;

const placeholders = [
  "CANDIDATE_NAME", "PROFESSIONAL_SUMMARY",
  "SKILL_CATEGORY_1", "SKILL_CONTENT_1",
  "SKILL_CATEGORY_2", "SKILL_CONTENT_2",
  "SKILL_CATEGORY_3", "SKILL_CONTENT_3",
  "SKILL_CATEGORY_4", "SKILL_CONTENT_4",
  "SKILL_CATEGORY_5", "SKILL_CONTENT_5",
  "SKILL_CATEGORY_6", "SKILL_CONTENT_6",
  "PROJECT_NUMBER_1", "PROJECT_TITLE_1", "PROJECT_DESCRIPTION_1", "PROJECT_RESPONSIBILITIES_1", "PROJECT_TECHSTACK_1",
  "PROJECT_NUMBER_2", "PROJECT_TITLE_2", "PROJECT_DESCRIPTION_2", "PROJECT_RESPONSIBILITIES_2", "PROJECT_TECHSTACK_2",
  "PROJECT_NUMBER_3", "PROJECT_TITLE_3", "PROJECT_DESCRIPTION_3", "PROJECT_RESPONSIBILITIES_3", "PROJECT_TECHSTACK_3",
  "PROJECT_NUMBER_4", "PROJECT_TITLE_4", "PROJECT_DESCRIPTION_4", "PROJECT_RESPONSIBILITIES_4", "PROJECT_TECHSTACK_4",
  "PROJECT_NUMBER_5", "PROJECT_TITLE_5", "PROJECT_DESCRIPTION_5", "PROJECT_RESPONSIBILITIES_5", "PROJECT_TECHSTACK_5",
  "PROJECT_NUMBER_6", "PROJECT_TITLE_6", "PROJECT_DESCRIPTION_6", "PROJECT_RESPONSIBILITIES_6", "PROJECT_TECHSTACK_6",
  "EDUCATION_DEGREE_1", "EDUCATION_INSTITUTE_1", "EDUCATION_YEAR_1",
  "EDUCATION_DEGREE_2", "EDUCATION_INSTITUTE_2", "EDUCATION_YEAR_2"
];

const requests = placeholders.map(key => ({
  replaceAllText: {
    containsText: {
      text: `{{${key}}}`,
      matchCase: true
    },
    replaceText: data[key] || ""
  }
}));

// Return single object (not array) when "Run Once for Each Item"
return {  json: { docId,    body: { requests }}};  // wrap it here
